diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
index d4a2fe5e37ef..3d311a9faa6d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -818,6 +818,9 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
     Constant *C;
     if (match(Src, m_OneUse(m_LShr(m_Value(X), m_ImmConstant(C))))) {
       // trunc (lshr X, C) to i1 --> icmp ne (and X, C'), 0
+      // When C is the sign bit position, use icmp slt for better CSE
+      if (cast<ConstantInt>(C)->equalsInt(SrcWidth - 1))
+        return new ICmpInst(ICmpInst::ICMP_SLT, X, Zero);
       Constant *One = ConstantInt::get(SrcTy, APInt(SrcWidth, 1));
       Value *MaskC = Builder.CreateShl(One, C);
       Value *And = Builder.CreateAnd(X, MaskC);
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 73ba0f78e805..8dc963423d77 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3479,6 +3479,25 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
     }
   }

+  // select (not V), V, false -> false
+  // Because: if V is true: select false, true, false = false
+  //          if V is false: select true, false, false = false
+  if (match(FalseVal, m_Zero()) && match(CondVal, m_Not(m_Specific(TrueVal))))
+    return replaceInstUsesWith(SI, Zero);
+
+  // select (xor (trunc (lshr X, bitwidth-1) to i1), true), (icmp slt X, 0), false -> false
+  // This handles the case where the condition checks the sign bit via trunc(lshr)
+  // and the true value checks it via icmp slt - both are equivalent.
+  if (match(FalseVal, m_Zero())) {
+    Value *X, *CmpX;
+    const APInt *ShiftAmt;
+    ICmpInst::Predicate Pred;
+    if (match(CondVal, m_OneUse(m_Xor(m_OneUse(m_Trunc(m_LShr(m_Value(X), m_APInt(ShiftAmt)))), m_One()))) &&
+        match(TrueVal, m_ICmp(Pred, m_Value(CmpX), m_ZeroInt())) &&
+        Pred == ICmpInst::ICMP_SLT && X == CmpX &&
+        ShiftAmt->getLimitedValue() == X->getType()->getScalarSizeInBits() - 1)
+      return replaceInstUsesWith(SI, Zero);
+  }
   return nullptr;
 }

@@ -3488,7 +3507,6 @@ static bool isSafeToRemoveBitCeilSelect(ICmpInst::Predicate Pred, Value *Cond0,
                                         const APInt *Cond1, Value *CtlzOp,
                                         unsigned BitWidth,
                                         bool &ShouldDropNoWrap) {
-  // The challenge in recognizing std::bit_ceil(X) is that the operand is used
   // for the CTLZ proper and select condition, each possibly with some
   // operation like add and sub.
   //

